// ABYSS 深淵海溝 — ground decal + standing decor pack.
// Ground decals (decal_abyss_*): low-contrast seabed marks, blended toward the
// biome's own floor tones (see biomes.js 'abyss': floor #0f3046 / floor2 #143b54).
// No outlines on decals; at most two carry a faint translucent glow accent
// (pale blue-white plankton motes / a glow-seam crack) — never bright
// green/teal so they never read as pickups.
// Standing decor (bdx_abyss_*): two coral variants (a wide lattice fan +
// stubby finger/horn coral, both distinct from the existing bd_abyss_coral
// branching coral), a gently swaying anemone, and a sunken ship plank —
// all in the same P.ocean/P.coral/P.abyss family, kept dark, glow restrained.

// ── shared floor-tone anchors (from biomes.js ABYSS entry) ─────────────────
const AB_F1 = '#0f3046';   // biome floor
const AB_F2 = '#143b54';   // biome floor2
const AB_SHELL = mix(P.sand, AB_F2, 0.55);   // shell fragments muted toward the seabed
const AB_BONE  = mix(P.bone, AB_F2, 0.55);   // bleached bits, dimmed for low contrast

// ============================ GROUND DECALS ============================
defineSprite('decal_abyss_ripple', 14, 6, (p) => {            // faint silt ripple bands
  p.ellipse(7, 3, 6, 2.6, lighten(AB_F1, 0.1));
  p.hline(2, 11, 2, lighten(AB_F1, 0.14));
  p.hline(1, 12, 4, darken(AB_F1, 0.12));
  p.hline(3, 9, 3, lighten(AB_F2, 0.1));
}, { anchor: 'center' });

defineSprite('decal_abyss_silt', 12, 8, (p) => {              // soft silt blotch
  p.ellipse(6, 4, 5, 3, darken(AB_F2, 0.1));
  p.ellipse(6, 4, 3.4, 2, lighten(AB_F2, 0.1));
  p.speckle(2, 2, 8, 4, darken(AB_F1, 0.16), 4, 21);
}, { anchor: 'center' });

defineSprite('decal_abyss_shellbits', 10, 6, (p) => {         // scattered shell fragments
  p.ellipse(3, 4, 2, 1, darken(AB_SHELL, 0.12));
  p.ellipse(7, 3, 1.6, 1, darken(AB_BONE, 0.16));
  p.px(5, 4, darken(AB_SHELL, 0.18));
  p.px(2, 3, lighten(AB_SHELL, 0.1));
  p.px(8, 4, darken(AB_BONE, 0.18));
}, { anchor: 'center' });

defineSprite('decal_abyss_kelpstrand', 14, 5, (p) => {        // flat fallen kelp strand
  p.line(1, 3, 12, 2, darken(P.ocean, 0.14));
  p.line(1, 2, 12, 1, darken(P.ocean, 0.18));
  p.px(4, 3, darken(P.oceanD, 0.1));
  p.px(9, 1, darken(P.oceanD, 0.1));
}, { anchor: 'center' });

defineSprite('decal_abyss_pebbles', 10, 6, (p) => {           // rounded pebble cluster
  p.ellipse(3, 4, 1.6, 1.2, darken(AB_F2, 0.14));
  p.ellipse(6, 3, 1.8, 1.3, lighten(AB_F2, 0.1));
  p.ellipse(8, 4, 1.2, 1, darken(AB_F1, 0.18));
  p.px(6, 2, lighten(AB_F2, 0.14));
}, { anchor: 'center' });

defineSprite('decal_abyss_motes', 8, 6, (p) => {              // drifting plankton motes (faint, pale blue-white)
  p.px(2, 3, withAlpha(P.hiSky, 0.5));
  p.px(5, 2, withAlpha(P.rimCool, 0.4));
  p.px(6, 4, withAlpha(P.hiSky, 0.35));
}, { anchor: 'center' });

defineSprite('decal_abyss_crack', 12, 5, (p) => {             // seabed fissure with a faint glow seam
  p.line(1, 4, 10, 1, darken(AB_F1, 0.18));
  p.line(2, 4, 9, 2, darken(AB_F1, 0.14));
  p.px(5, 2, withAlpha(P.oceanL, 0.3));
  p.px(6, 2, withAlpha(P.oceanL, 0.22));
}, { anchor: 'center' });

defineSprite('decal_abyss_bonechip', 8, 5, (p) => {           // tiny bleached bone fragment
  p.ellipse(4, 3, 2, 1.2, darken(AB_BONE, 0.18));
  p.px(3, 2, darken(AB_BONE, 0.12));
  p.px(5, 3, darken(AB_BONE, 0.18));
}, { anchor: 'center' });

// ============================ STANDING DECOR ============================
defineSprite('bdx_abyss_fancoral', 18, 20, (p) => {           // wide sea-fan (gorgonian) coral lattice
  p.softShadow(9, 19, 7, 2, 0.4);
  p.ellipse(9, 19, 5, 2, P.abyss);                            // holdfast base
  p.vline(14, 19, 9, darken(P.coral, 0.25));                  // short stalk (fan hub down to holdfast; vline is y0,y1,x)
  // fan lattice: radiating branches forming a wide flat fan
  p.line(9, 14, 2, 4, P.coral); p.line(9, 14, 5, 2, P.coral); p.line(9, 14, 9, 1, P.coral);
  p.line(9, 14, 13, 2, P.coral); p.line(9, 14, 16, 4, P.coral);
  // cross-struts giving it a net/lattice look
  p.line(4, 8, 14, 8, darken(P.coral, 0.15));
  p.line(3, 6, 15, 6, darken(P.coral, 0.2));
  p.px(2, 4, lighten(P.coral, 0.2)); p.px(16, 4, lighten(P.coral, 0.2)); p.px(9, 1, P.sakuraL);
  p.rimLight(P.rimCool, 0.35);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineSprite('bdx_abyss_hornfingers', 14, 16, (p) => {        // stubby finger/horn coral cluster
  p.softShadow(7, 15, 6, 1.6, 0.4);
  p.ellipse(7, 15, 5, 2, P.abyss);
  // three stubby knobbed fingers of varying height
  p.rect(2, 7, 3, 8, darken(P.coral, 0.1)); p.rect(2, 7, 1, 8, lighten(P.coral, 0.1));
  p.rect(6, 4, 3, 11, P.coral); p.rect(6, 4, 1, 11, lighten(P.coral, 0.15));
  p.rect(10, 8, 3, 7, darken(P.coral, 0.15)); p.rect(10, 8, 1, 7, P.coral);
  // rounded knobby tips
  p.ellipse(3, 7, 1.6, 1.4, lighten(P.coral, 0.15));
  p.ellipse(7, 4, 1.8, 1.4, lighten(P.coral, 0.22));
  p.ellipse(11, 8, 1.6, 1.4, P.coral);
  p.px(7, 3, P.sakuraL);
  p.rimLight(P.rimCool, 0.3);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineAnim('bdx_abyss_anemone', 16, 18, 3, (p, f) => {        // gently swaying sea anemone
  p.softShadow(8, 17, 6, 1.6, 0.4);
  p.ellipse(8, 16, 5, 2.4, darken(P.abyss, 0.1));             // base disc
  const sway = [0, 1, -1][f];
  // ring of tentacles, alternating magenta/sakura, tips drifting with sway
  for (let i = 0; i < 7; i++) {
    const bx = 3 + i * 1.7;
    const h = 6 + (i % 3);
    const tx = bx + sway * (i % 2 === 0 ? 1 : -1) * 0.6;
    const col = i % 2 === 0 ? P.magenta : P.sakura;
    p.line(bx, 15, tx, 15 - h, col);
    p.px(tx, 15 - h, lighten(col, 0.2));
  }
  p.ellipse(8, 14, 2.4, 1.6, darken(P.abyss, 0.05));          // central mouth
  p.glow(8, 14, 1.6, P.magenta, 0.25, 2);
  p.px(8, 14, P.magentaD);
  p.rimLight(P.rimCool, 0.3);
  p.outline(P.ink);
}, { anchor: 'feet', fps: 3 });

defineSprite('bdx_abyss_wreckplank', 20, 14, (p) => {         // sunken ship plank, leaning out of the seabed
  p.softShadow(10, 13, 9, 2, 0.42);
  p.ellipse(10, 13, 9, 2.4, P.abyss);
  // leaning plank: dark waterlogged wood
  p.rect(3, 8, 15, 4, mix(P.woodD, P.abyss, 0.35));
  p.rect(3, 8, 15, 1, mix(P.wood, P.abyss, 0.2));
  p.line(3, 12, 1, 6, mix(P.woodD, P.abyss, 0.3));            // propped end lifting off the seabed
  p.line(18, 12, 19, 9, mix(P.woodD, P.abyss, 0.4));
  // rusted iron band
  p.rect(9, 7, 3, 6, darken(P.iron, 0.15)); p.px(9, 7, lighten(P.iron, 0.1));
  // algae streaks + barnacle clusters
  p.speckle(4, 8, 13, 4, P.oceanD, 6, 59);
  p.px(6, 9, P.moss); p.px(7, 9, darken(P.moss, 0.15));
  p.ellipse(14, 9, 1.6, 1.2, P.sand); p.ellipse(16, 10, 1.4, 1, P.sandD);
  p.px(14, 8, lighten(P.sand, 0.15));
  p.rimLight(P.rimCool, 0.3);
  p.outline(P.ink);
}, { anchor: 'feet' });

// ============================ REGISTRATION ============================
registerDecals('abyss', [
  'decal_abyss_ripple',
  'decal_abyss_silt',
  'decal_abyss_shellbits',
  'decal_abyss_kelpstrand',
  'decal_abyss_pebbles',
  'decal_abyss_motes',
  'decal_abyss_crack',
  'decal_abyss_bonechip',
]);
(DECOR_SETS['abyss'] = DECOR_SETS['abyss'] || []).push(
  'bdx_abyss_fancoral',
  'bdx_abyss_hornfingers',
  'bdx_abyss_anemone',
  'bdx_abyss_wreckplank',
);
(DECOR_CLUSTERS['abyss'] = DECOR_CLUSTERS['abyss'] || []).push(
  'bdx_abyss_fancoral',
  'bdx_abyss_hornfingers',
);

